function mergeConcat(a, b) {
  return a.concat(b).filter((item, index, self) =>
    self.indexOf(item) === index
  );
}

function mergeTyped(a, b) {
  const merged = new Int32Array(a.length + b.length);
  merged.set(a);
  merged.set(b, a.length);
  return Array.from(new Set(merged));
}
